// src/components/Navbar.jsx
import { useState, useEffect } from 'react';
import { personal } from '../data/portfolio';

const links = [
  { href: '#about',      label: 'About' },
  { href: '#skills',     label: 'Skills' },
  { href: '#experience', label: 'Experience' },
  { href: '#education',  label: 'Education' },
  { href: '#contact',    label: 'Contact' },
];

const styles = {
  nav: {
    position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100,
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    padding: '0 5%', height: 68,
    borderBottom: '1px solid var(--border)',
    transition: 'background 0.3s, backdrop-filter 0.3s',
  },
  navScrolled: {
    background: 'rgba(12,12,14,0.88)',
    backdropFilter: 'blur(20px)',
  },
  navTop: {
    background: 'transparent',
  },
  logo: {
    fontFamily: 'var(--font-head)',
    fontWeight: 800,
    fontSize: 18,
    letterSpacing: '-0.5px',
    color: 'var(--text)',
  },
  logoAccent: { color: 'var(--accent)' },
  linksList: {
    display: 'flex', gap: 36, listStyle: 'none',
  },
  link: {
    fontSize: 12, fontWeight: 500,
    letterSpacing: '0.1em', textTransform: 'uppercase',
    color: 'var(--text2)',
    transition: 'color 0.2s',
    cursor: 'pointer',
  },
  cta: {
    background: 'var(--accent)',
    color: '#fff', border: 'none',
    padding: '9px 22px', borderRadius: 6,
    fontFamily: 'var(--font-body)',
    fontSize: 13, fontWeight: 500,
    cursor: 'pointer',
    transition: 'background 0.2s, transform 0.15s',
    textDecoration: 'none',
    display: 'inline-block',
  },
};

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <nav style={{ ...styles.nav, ...(scrolled ? styles.navScrolled : styles.navTop) }}>
      <a href="#hero" style={styles.logo}>
        {personal.initials}<span style={styles.logoAccent}>.</span>
      </a>

      <ul style={styles.linksList}>
        {links.map((l) => (
          <li key={l.href}>
            <a
              href={l.href}
              style={styles.link}
              onMouseEnter={e => (e.target.style.color = 'var(--text)')}
              onMouseLeave={e => (e.target.style.color = 'var(--text2)')}
            >
              {l.label}
            </a>
          </li>
        ))}
      </ul>

      <a
        href={`mailto:${personal.contact.email}`}
        style={styles.cta}
        onMouseEnter={e => { e.target.style.background = 'var(--accent2)'; e.target.style.transform = 'translateY(-1px)'; }}
        onMouseLeave={e => { e.target.style.background = 'var(--accent)'; e.target.style.transform = 'none'; }}
      >
        Hire me
      </a>
    </nav>
  );
}
